<?php require_once __DIR__.'/../app/poster.php'; $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf(); try{ if(isset($_POST['interval'])) set_setting('cron_interval_minutes',(string)(int)$_POST['interval']); if(isset($_POST['rss'])) {$r=fetch_all_feeds();$msg='RSS取得完了 OK '.$r['ok'].' / NG '.$r['ng']; set_setting('last_rss_cron',date('Y-m-d H:i:s'));} if(isset($_POST['post'])) {$id=run_post();$msg='投稿処理完了 ID '.$id; set_setting('last_post_cron',date('Y-m-d H:i:s'));} }catch(Throwable $e){$msg='エラー: '.$e->getMessage(); log_event('error','手動Cron失敗',$e->getMessage());}} admin_header('Cron設定'); if($msg)echo'<p class=notice>'.e($msg).'</p>'; $php=PHP_BINARY?:'php'; echo'<form method=post><input type=hidden name=csrf value='.csrf_token().'><label>実行間隔(分)<input name=interval value="'.e(setting('cron_interval_minutes',60)).'"></label><button>保存</button><button name=rss value=1>RSS取得実行</button><button name=post value=1>livedoor投稿実行</button></form><div class=card><h3>シンサーバー向けCron例</h3><p>RSS取得: <code>'.$php.' '.APP_ROOT.'/cron/fetch.php</code></p><p>投稿: <code>'.$php.' '.APP_ROOT.'/cron/post.php</code></p><p>URL実行: <code>'.e(current_origin().app_url('/cron/fetch.php')).'</code></p><p>最終RSS実行: '.e(setting('last_rss_cron','-')).'</p><p>最終投稿実行: '.e(setting('last_post_cron','-')).'</p></div>'; admin_footer();
